// API routes FIRST
app.post("/api/chat", async (req, res) => {
  const { message, history } = req.body;

  if (!message) {
    return res.status(400).json({ error: "Message is required" });
  }

  try {
    const formattedHistory = (history || []).map((h: any) => ({
      role: h.role,
      parts: [{ text: h.text }]
    }));

    // Inject system instruction dynamically
    const contents = [
      ...formattedHistory,
      { role: "user", parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    const reply = response.text || "죄송합니다. 적절한 응답을 생성하지 못했습니다. 다시 말씀해 주실 수 있나요?";
    res.json({ reply });

  } catch (error: any) {
    console.error("Gemini routing error:", error);
    res.status(500).json({ error: "Gemini API failed to proceed", details: error.message });
  }
});

// Vite middleware configuration for serving or rendering in production
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`AIXON full-stack server running on http://0.0.0.0:${PORT}`);
  });
}

startServer();
